import{_ as n,o as s,c as e,ag as p}from"./chunks/framework.DNt_9s2P.js";const u=JSON.parse('{"title":"アーキテクチャ","description":"","frontmatter":{},"headers":[],"relativePath":"guide/architecture.md","filePath":"guide/architecture.md"}'),l={name:"guide/architecture.md"};function i(t,a,c,r,o,d){return s(),e("div",null,[...a[0]||(a[0]=[p(`<h1 id="アーキテクチャ" tabindex="-1">アーキテクチャ <a class="header-anchor" href="#アーキテクチャ" aria-label="Permalink to &quot;アーキテクチャ&quot;">​</a></h1><p>Selah の技術的なアーキテクチャの概要です。</p><h2 id="全体構成" tabindex="-1">全体構成 <a class="header-anchor" href="#全体構成" aria-label="Permalink to &quot;全体構成&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>+------------------------------------------+</span></span>
<span class="line"><span>|            Selah (Tauri 2)               |</span></span>
<span class="line"><span>+------------------------------------------+</span></span>
<span class="line"><span>|  Frontend (WebView)                      |</span></span>
<span class="line"><span>|  +------------------------------------+  |</span></span>
<span class="line"><span>|  | Svelte 5 + TypeScript              |  |</span></span>
<span class="line"><span>|  | Vite (Build)                       |  |</span></span>
<span class="line"><span>|  +------------------------------------+  |</span></span>
<span class="line"><span>+------------------------------------------+</span></span>
<span class="line"><span>|  Backend (Rust)                          |</span></span>
<span class="line"><span>|  +------------------------------------+  |</span></span>
<span class="line"><span>|  | Tauri Commands                     |  |</span></span>
<span class="line"><span>|  | HTTP Client (reqwest)              |  |</span></span>
<span class="line"><span>|  | HTML Parser (scraper)              |  |</span></span>
<span class="line"><span>|  | SQLite (rusqlite, WAL)             |  |</span></span>
<span class="line"><span>|  | AI Client (OpenAI / Gemini)        |  |</span></span>
<span class="line"><span>|  +------------------------------------+  |</span></span>
<span class="line"><span>+------------------------------------------+</span></span>
<span class="line"><span>|  External Services                       |</span></span>
<span class="line"><span>|  +------------------------------------+  |</span></span>
<span class="line"><span>|  | KWIC / Luna / Microsoft 365       |  |</span></span>
<span class="line"><span>|  | OpenAI API / Google Gemini API    |  |</span></span>
<span class="line"><span>|  | Open-Meteo API                    |  |</span></span>
<span class="line"><span>|  +------------------------------------+  |</span></span>
<span class="line"><span>+------------------------------------------+</span></span></code></pre></div><h2 id="cookie-bridge-認証" tabindex="-1">Cookie Bridge 認証 <a class="header-anchor" href="#cookie-bridge-認証" aria-label="Permalink to &quot;Cookie Bridge 認証&quot;">​</a></h2><p>Selah は独自の <strong>Cookie Bridge</strong> 方式で SSO 認証を処理します。</p><ol><li>内蔵 WebView (WKWebView / WebView2) で関学 SSO のログインフォームを表示</li><li>ユーザーが SSO でログイン</li><li>WebView から取得した Cookie を Rust 側の HTTP クライアント (<code>reqwest</code>) に橋渡し</li><li>KG-Course・Luna・KWIC の 3 系統を一度のログインで認証</li></ol><h2 id="データフロー" tabindex="-1">データフロー <a class="header-anchor" href="#データフロー" aria-label="Permalink to &quot;データフロー&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>SSO Login</span></span>
<span class="line"><span>    |</span></span>
<span class="line"><span>    v</span></span>
<span class="line"><span>Cookie Bridge --&gt; reqwest HTTP Client</span></span>
<span class="line"><span>    |                    |</span></span>
<span class="line"><span>    +-----&gt; KWIC API     |</span></span>
<span class="line"><span>    +-----&gt; Luna API     |</span></span>
<span class="line"><span>    +-----&gt; Mail API     |</span></span>
<span class="line"><span>                         v</span></span>
<span class="line"><span>                   HTML Scraping / JSON Parse</span></span>
<span class="line"><span>                         |</span></span>
<span class="line"><span>                         v</span></span>
<span class="line"><span>                   SQLite Cache (WAL)</span></span>
<span class="line"><span>                         |</span></span>
<span class="line"><span>                         v</span></span>
<span class="line"><span>                   Tauri Commands (IPC)</span></span>
<span class="line"><span>                         |</span></span>
<span class="line"><span>                         v</span></span>
<span class="line"><span>                   Svelte Frontend</span></span></code></pre></div><h2 id="ローカルキャッシュ戦略" tabindex="-1">ローカルキャッシュ戦略 <a class="header-anchor" href="#ローカルキャッシュ戦略" aria-label="Permalink to &quot;ローカルキャッシュ戦略&quot;">​</a></h2><ul><li><strong>SWR (Stale-While-Revalidate)</strong> 方式を採用</li><li>起動時はキャッシュデータを即座に表示し、バックグラウンドで最新データを取得</li><li>ネットワーク不通時はキャッシュデータでフォールバック</li><li>SQLite の WAL (Write-Ahead Logging) モードで読み書きの並行処理を実現</li></ul><h2 id="セッション管理" tabindex="-1">セッション管理 <a class="header-anchor" href="#セッション管理" aria-label="Permalink to &quot;セッション管理&quot;">​</a></h2><ul><li>セッション有効期限の自動検証</li><li>期限切れ時の自動再ログインフロー</li><li>セキュアなクレデンシャル保存（macOS: Keychain / Windows: Credential Store）</li></ul>`,13)])])}const g=n(l,[["render",i]]);export{u as __pageData,g as default};
